    private calculateRefocus2(old:ZoomImage, next:ZoomImage, oldTile:ZoomImageTile)
    {
        let transform:Point = this.align(next, oldTile);

        this.refocusToScale = next.rect.localScale;
        this.refocusToPosition = next.rect.localPosition;
        this.refocusFromScale = new Point(transform.z, transform.z);
        this.refocusFromPosition = new Point(transform.x, transform.y);
    }

    /**
     * Aligns the given image so that the tile's screen area matches the same area in the image. The tile must be part of the image.
     * The image must be fitted inside the current viewport before aligning.
     * 
     * @param img 
     * @param tile 
     * @returns (localPosition.x, localPosition.y, scale) as Point (x,y,z)
     */
    private align(img:ZoomImage, tile:ZoomImageTile):Point
    {
        let result:Point = new Point();

        // Target screen area
        let targetRect:Rectangle = tile.sprite.rect.rect;

        // Source screen area
        let sourceRect:Rectangle = new Rectangle(img.rect.screenWidth * tile.uw, img.rect.screenHeight * tile.vh, img.rect.screenPosition.x + (tile.u - 0.5) * img.rect.screenWidth, img.rect.screenPosition.y + (tile.v - 0.5) * img.rect.screenHeight);

        // targetScale
        result.z = targetRect.width / sourceRect.width;

        // Temporarily scale the image
        img.rect.localScale = new Point(result.z, result.z);
        img.rect.recalculate();

        // Source screen area after scaled up
        let sourceRect2:Rectangle = new Rectangle(img.rect.screenWidth * tile.uw, img.rect.screenHeight * tile.vh, img.rect.screenPosition.x + (tile.u - 0.5) * img.rect.screenWidth, img.rect.screenPosition.y + (tile.v - 0.5) * img.rect.screenHeight);        

        // Offset
        let screenOffset:Point = targetRect.origin.sub(sourceRect2.origin);

        // Target screen position of img
        let TSP:Point = img.rect.screenPosition.add(screenOffset);

        // Target local position of img
        let TLP:Point = img.rect.parent.screenToLocal(TSP);

        result.x = TLP.x;
        result.y = TLP.y;

        // Scale the image back
        img.rect.localScale = new Point(1,1);
        img.rect.recalculate();

        return result;
    }

