    private updateRefocus2()
    {
        let opacityStart:number = 0.4;
        let movementStart:number = 0.3;

        if (this.nextImage.original.status == ResourceStatus.Loaded)
        {
            let t = this.refocusCounter / this.settings.refocusDuration;
            
            // Start disappearing tiles if it's their time
            this.currentImage.eachTile ( (t:ZoomImageTile) => {
                if (t.hideAfter > 0 && t.hideAfter <= this.refocusCounter)
                {
                    t.sprite.fadeOut = 0.05;
                    t.sprite.fadeIn = 0;
                    t.hideAfter = 0;
                }
            });

            // Animate next image appearance
            if (t > opacityStart)
            {
                this.nextImage.original.opacity = (t - opacityStart) / (1 - opacityStart);
            }
            if (t > movementStart)
            {                                    
                this.nextImage.rect.localScale = this.refocusFromScale.int(this.refocusToScale, (t - movementStart) / (1 - movementStart));
                this.nextImage.rect.localPosition = this.refocusFromPosition.int(this.refocusToPosition, (t - movementStart) / (1 - movementStart));
                this.nextImage.rect.recalculate();                        
            }

            this.refocusCounter += Time.deltaTime;

            // Finish transition
            if (this.refocusCounter >= this.settings.refocusDuration)        
            {
                this.switchNextImage();

                if (this.focusTile != null)
                {
                    this.sprites.remove(this.focusTile.sprite);
                    this.focusTile = null;
                }
            }
        }        
    }

    private switchNextImage()
    {
        this.sprites.remove(this.currentImage.original);
        this.sprites.remove(this.currentImage.mosaic);
        this.currentImage.eachTile( (t) => { if (t.sprite) this.sprites.remove(t.sprite);});
        this.currentImage.status = ResourceStatus.DefinitionLoaded;
        this.currentImage.fit(this.width, this.height);

        this.currentImage = this.nextImage;
        this.currentImage.rect.localPosition = new Point(0.5, 0.5);
        this.currentImage.fit(this.width, this.height);        
        this.currentImage.setZoom(1);
        this.nextImage = null;
        this.phase = Phase.Original;
        this._zoom = 1;
        this.refocusCounter = 0;
        this.gui.setInfo(this.currentImage.definition);
        this.gui.showInfo(this.settings.showInfoDuration);
    }

    private connectElectron()
    {
        // Check if Electron is present
        console.log("Looking for Electron IPC");
        if ((<any>window).require)
        {
            try
            {
                this.ipc = (<any>window).require('electron').ipcRenderer;
            } 
            catch (e)
            {
                this.ipc = null;
                //throw e;
                
            }
        } 
        else
        {
            console.warn('Electron\'s IPC was not loaded');
        }

        if (!this.ipc)
        {
            console.log('Electron IPC is not present');
            return;
        }

        // Create home button
        let a = document.createElement("a");
        this.container.appendChild(a);
        a.id = "homebutton";
        a.innerText = "Výber aplikácie";
        a.onclick = () => {this.close();}

        // Get standalone config
        let config = this.ipc.sendSync("get-config");
        if (config)
            this.settings.fill(config);
    }
